SELECT setval('artists_id_seq', (SELECT MAX(id) FROM artists));
SELECT setval('albums_id_seq',  (SELECT MAX(id) FROM albums));
SELECT setval('songs_id_seq',   (SELECT MAX(id) FROM songs));